// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FHE, ebool, euint64, externalEbool} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {CharterShares} from "./CharterShares.sol";

/// @title CharterResolutionsV3 — shareholder-proposed resolutions
/// @notice The third governance module in Charter's live-upgraded lineage (v1 -> v2 -> v3), each
/// swapped in through {CharterShares.setModule} without touching the share token. V3 keeps V2's
/// outcome-only privacy model and participation quorum, and additionally opens proposal rights to
/// **any self-delegated shareholder** (not just the issuer). A holder can therefore drive the whole
/// governance loop themselves: activate voting, propose, vote, and settle — all confidential, with
/// only the pass/fail outcome ever disclosed.
contract CharterResolutionsV3 is ZamaEthereumConfig {
    struct Resolution {
        string description;
        uint48 snapshot;
        uint48 deadline;
        euint64 forVotes;
        euint64 againstVotes;
        ebool passedHandle;
        uint32 voterCount;
        bool quorumReached;
        bool tallyRequested;
        bool resolved;
        bool passed;
    }

    CharterShares public immutable SHARES;
    /// @notice Minimum distinct voters required for a resolution to reach quorum and be settleable.
    uint32 public immutable MIN_VOTERS;

    Resolution[] private _resolutions;
    mapping(uint256 resolutionId => mapping(address voter => bool)) public hasVoted;

    event ResolutionProposed(uint256 indexed id, address indexed proposer, string description, uint48 deadline);
    event VoteCast(uint256 indexed id, address voter);
    event TallyRequested(uint256 indexed id);
    event ResolutionSettled(uint256 indexed id, bool passed, bool quorumReached);

    error ResolutionsCannotPropose(address caller);
    error ResolutionsVotingClosed(uint256 id);
    error ResolutionsVotingNotStarted(uint256 id);
    error ResolutionsVotingNotEnded(uint256 id);
    error ResolutionsAlreadyVoted(uint256 id, address voter);
    error ResolutionsNoVotingPower(address voter);
    error ResolutionsNoTallyRequested(uint256 id);
    error ResolutionsAlreadyResolved(uint256 id);
    error ResolutionsQuorumNotReached(uint256 id);

    constructor(CharterShares shares, uint32 minVoters) {
        SHARES = shares;
        MIN_VOTERS = minVoters;
    }

    /// @notice True if `account` may open a resolution: the issuer, or any self-delegated shareholder.
    function canPropose(address account) public view returns (bool) {
        return SHARES.isAdmin(account) || SHARES.isAgent(account) || SHARES.delegates(account) != address(0);
    }

    function resolutionCount() external view returns (uint256) {
        return _resolutions.length;
    }

    function getResolution(uint256 id) external view returns (Resolution memory) {
        return _resolutions[id];
    }

    /// @notice Proposes a resolution. Open to the issuer or any shareholder who has activated voting
    /// power (self-delegated). Voting power snapshots at the current clock; voting opens next block.
    function propose(string calldata description, uint48 votingPeriod) external returns (uint256 id) {
        require(canPropose(msg.sender), ResolutionsCannotPropose(msg.sender));
        uint48 snapshot = SHARES.clock();

        id = _resolutions.length;
        _resolutions.push();
        Resolution storage r = _resolutions[id];
        r.description = description;
        r.snapshot = snapshot;
        r.deadline = snapshot + votingPeriod;

        euint64 zero = FHE.asEuint64(0);
        FHE.allowThis(zero);
        r.forVotes = zero;
        r.againstVotes = zero;

        emit ResolutionProposed(id, msg.sender, description, r.deadline);
    }

    /// @notice Casts an encrypted for/against vote weighted by the voter's snapshot
    /// holdings. Neither the direction nor the weight is revealed.
    function castVote(uint256 id, externalEbool encryptedSupport, bytes calldata inputProof) external {
        Resolution storage r = _resolutions[id];
        uint48 currentClock = SHARES.clock();
        require(currentClock > r.snapshot, ResolutionsVotingNotStarted(id));
        require(currentClock <= r.deadline, ResolutionsVotingClosed(id));
        require(!hasVoted[id][msg.sender], ResolutionsAlreadyVoted(id, msg.sender));
        hasVoted[id][msg.sender] = true;
        r.voterCount += 1;

        euint64 weight = SHARES.getPastVotes(msg.sender, r.snapshot);
        require(FHE.isInitialized(weight), ResolutionsNoVotingPower(msg.sender));
        SHARES.getHandleAllowance(euint64.unwrap(weight), address(this), false);

        ebool support = FHE.fromExternal(encryptedSupport, inputProof);
        euint64 zero = FHE.asEuint64(0);

        r.forVotes = FHE.add(r.forVotes, FHE.select(support, weight, zero));
        r.againstVotes = FHE.add(r.againstVotes, FHE.select(support, zero, weight));
        FHE.allowThis(r.forVotes);
        FHE.allowThis(r.againstVotes);

        emit VoteCast(id, msg.sender);
    }

    /// @notice After the deadline, either makes the pass/fail outcome publicly decryptable (if the
    /// quorum was met) or resolves the resolution as failed for lack of quorum without disclosing
    /// anything.
    function requestTally(uint256 id) external {
        Resolution storage r = _resolutions[id];
        require(SHARES.clock() > r.deadline, ResolutionsVotingNotEnded(id));
        require(!r.resolved, ResolutionsAlreadyResolved(id));
        r.tallyRequested = true;

        if (r.voterCount >= MIN_VOTERS) {
            r.quorumReached = true;
            ebool passedEnc = FHE.gt(r.forVotes, r.againstVotes);
            FHE.allowThis(passedEnc);
            FHE.makePubliclyDecryptable(passedEnc);
            r.passedHandle = passedEnc;
        } else {
            // Quorum not reached: the resolution fails, and no tally is disclosed.
            r.resolved = true;
            r.passed = false;
        }
        emit TallyRequested(id);
    }

    /// @notice Settles a quorate resolution with the decrypted outcome and its KMS proof.
    /// Anyone may relay; forged cleartexts revert in {FHE.checkSignatures}.
    function settle(uint256 id, bool passedClear, bytes calldata decryptionProof) external {
        Resolution storage r = _resolutions[id];
        require(r.tallyRequested, ResolutionsNoTallyRequested(id));
        require(r.quorumReached, ResolutionsQuorumNotReached(id));
        require(!r.resolved, ResolutionsAlreadyResolved(id));

        bytes32[] memory handles = new bytes32[](1);
        handles[0] = ebool.unwrap(r.passedHandle);
        FHE.checkSignatures(handles, abi.encode(passedClear), decryptionProof);

        r.passed = passedClear;
        r.resolved = true;
        emit ResolutionSettled(id, passedClear, true);
    }
}

contracts/CharterShares.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FHE, euint64} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {EIP712} from "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import {IERC7984} from "@openzeppelin/confidential-contracts/interfaces/IERC7984.sol";
import {ERC7984} from "@openzeppelin/confidential-contracts/token/ERC7984/ERC7984.sol";
import {ERC7984Rwa} from "@openzeppelin/confidential-contracts/token/ERC7984/extensions/ERC7984Rwa.sol";
import {ERC7984Votes} from "@openzeppelin/confidential-contracts/token/ERC7984/extensions/ERC7984Votes.sol";
import {
    ERC7984ObserverAccess
} from "@openzeppelin/confidential-contracts/token/ERC7984/extensions/ERC7984ObserverAccess.sol";

/// @title CharterShares — a confidential share registry for a private company
/// @notice Company shares as an ERC7984 confidential token. Individual holdings are
/// encrypted on-chain; only the holder (and an observer they appoint, e.g. an auditor)
/// can decrypt them. Compliance controls (agent mint/burn, transfer restrictions,
/// freezing, forced transfers, pause) come from ERC7984Rwa. Checkpointed encrypted
/// voting power (ERC7984Votes) backs shareholder resolutions.
///
/// The total number of issued shares can be disclosed publicly through the Zama
/// decryption oracle with an on-chain KMS proof ("verifiable total, hidden individual
/// holdings"). The disclosed total is the record supply used by distribution modules
/// for pro-rata payout math on encrypted balances.
contract CharterShares is ZamaEthereumConfig, ERC7984Rwa, ERC7984ObserverAccess, ERC7984Votes {
    /// @notice Registered protocol modules (distributor, resolutions) allowed to
    /// receive scoped access to encrypted handles held by this contract.
    mapping(address module => bool) public isModule;

    /// @notice Total issued shares as last disclosed through the decryption oracle.
    uint64 public totalSharesOnRecord;
    /// @notice Clock value (block number) at which the record supply was finalized.
    uint48 public recordTimepoint;

    euint64 private _pendingSupplyHandle;
    uint48 private _lastSupplyChangeTimepoint;

    event ModuleSet(address indexed module, bool enabled);
    event SupplyDisclosureRequested(euint64 supplyHandle);
    event SupplyDisclosed(uint64 totalShares, uint48 recordTimepoint);

    error CharterNotModule(address caller);
    error CharterNoSupply();
    error CharterNoPendingDisclosure();

    constructor(
        string memory name_,
        string memory symbol_,
        string memory contractURI_,
        address admin
    ) ERC7984(name_, symbol_, contractURI_) ERC7984Rwa(admin) EIP712(name_, "1") {}

    /// @notice Shares are whole units — no decimals.
    function decimals() public pure override(IERC7984, ERC7984) returns (uint8) {
        return 0;
    }

    /// @notice Registers or removes a protocol module (distributor, resolutions).
    function setModule(address module, bool enabled) external onlyAdmin {
        isModule[module] = enabled;
        emit ModuleSet(module, enabled);
    }

    /// @notice Grants the calling module transient (same-transaction) ACL access to
    /// `account`'s encrypted balance and returns the balance handle. Used by the
    /// distributor to compute pro-rata payouts on encrypted holdings.
    function allowBalanceAccess(address account) external returns (euint64 balance) {
        require(isModule[msg.sender], CharterNotModule(msg.sender));
        balance = confidentialBalanceOf(account);
        if (FHE.isInitialized(balance)) {
            FHE.allowTransient(balance, msg.sender);
        }
    }

    /// @notice Starts public disclosure of the current total supply through the
    /// decryption oracle. The cleartext comes back via {finalizeSupplyDisclosure}
    /// with a KMS proof verified on-chain.
    function requestSupplyDisclosure() external onlyAgent {
        euint64 supply = confidentialTotalSupply();
        require(FHE.isInitialized(supply), CharterNoSupply());
        FHE.makePubliclyDecryptable(supply);
        _pendingSupplyHandle = supply;
        emit SupplyDisclosureRequested(supply);
    }

    /// @notice Finalizes a supply disclosure with the KMS decryption proof. Anyone may
    /// relay the proof; forged cleartexts revert in {FHE.checkSignatures}.
    function finalizeSupplyDisclosure(uint64 clearSupply, bytes calldata decryptionProof) external {
        euint64 pending = _pendingSupplyHandle;
        require(FHE.isInitialized(pending), CharterNoPendingDisclosure());

        bytes32[] memory handles = new bytes32[](1);
        handles[0] = euint64.unwrap(pending);
        FHE.checkSignatures(handles, abi.encode(clearSupply), decryptionProof);

        totalSharesOnRecord = clearSupply;
        recordTimepoint = clock();
        _pendingSupplyHandle = euint64.wrap(0);
        emit SupplyDisclosed(clearSupply, recordTimepoint);
    }

    /// @notice Returns true when shares were minted or burned after the last supply disclosure.
    function supplyDisclosureStale() public view returns (bool) {
        return _lastSupplyChangeTimepoint > recordTimepoint;
    }

    /// @dev Registered modules may request access to handles this contract holds ACL
    /// for (e.g. voting-power checkpoints read by the resolutions module).
    function _validateHandleAllowance(bytes32) internal view override returns (bool) {
        return isModule[msg.sender];
    }

    function confidentialTotalSupply()
        public
        view
        override(IERC7984, ERC7984, ERC7984Votes)
        returns (euint64)
    {
        return super.confidentialTotalSupply();
    }

    function supportsInterface(
        bytes4 interfaceId
    ) public view override(ERC7984, ERC7984Rwa) returns (bool) {
        return super.supportsInterface(interfaceId);
    }

    function _update(
        address from,
        address to,
        euint64 amount
    ) internal override(ERC7984Rwa, ERC7984ObserverAccess, ERC7984Votes) returns (euint64) {
        if (from == address(0) || to == address(0)) {
            _lastSupplyChangeTimepoint = clock();
        }
        return super._update(from, to, amount);
    }
}

contracts/ConfidentialTenderOffer.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FHE, euint64, externalEuint64} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {IERC7984} from "@openzeppelin/confidential-contracts/interfaces/IERC7984.sol";
import {CharterShares} from "./CharterShares.sol";

/// @title ConfidentialTenderOffer — a confidential share buyback module
/// @notice A registered CharterShares module that runs a sealed tender offer (share buyback): the
/// issuer offers to repurchase up to a public `maxShares` at a public `pricePerShare`, and holders
/// tender an **encrypted** quantity of shares. How many shares each holder offers to sell stays
/// private; only the aggregate tendered amount is disclosed after the deadline, with an on-chain KMS
/// proof. If the offer is oversubscribed, each holder's accepted quantity is scaled pro-rata on
/// ciphertext (accepted = tendered * maxShares / totalTendered); otherwise every tender is filled.
/// Accepted shares move from the holder to the issuer's treasury and the holder is paid in a
/// confidential payment token, all over encrypted amounts.
///
/// The holder consents by (1) approving this contract as an operator on the share token so the
/// buyback can pull the accepted shares, and (2) submitting an encrypted tender before the deadline.
contract ConfidentialTenderOffer is ZamaEthereumConfig {
    struct Offer {
        address treasury; // where repurchased shares go (the opener)
        address paymentToken; // confidential cash paid to sellers
        uint64 pricePerShare; // public price in payment-token units
        uint64 maxShares; // public cap the issuer will repurchase
        uint48 deadline; // block number after which tenders close
        euint64 totalTendered; // encrypted sum of all accepted-capped tenders
        bool totalRequested;
        bool totalSettled;
        uint64 totalTenderedClear; // disclosed aggregate, after settleTotal
    }

    CharterShares public immutable SHARES;

    Offer[] private _offers;
    mapping(uint256 offerId => mapping(address holder => euint64)) private _tender;
    mapping(uint256 offerId => mapping(address holder => bool)) public tendered;
    mapping(uint256 offerId => mapping(address holder => bool)) public claimed;

    event OfferOpened(uint256 indexed id, address indexed token, uint64 pricePerShare, uint64 maxShares, uint48 deadline);
    event Tendered(uint256 indexed id, address holder);
    event TotalRequested(uint256 indexed id);
    event TotalSettled(uint256 indexed id, uint64 totalTendered, bool oversubscribed);
    event Claimed(uint256 indexed id, address[] holders);

    error TenderNotIssuer(address caller);
    error TenderBadParams();
    error TenderClosed(uint256 id);
    error TenderNotClosed(uint256 id);
    error TenderAlready(uint256 id, address holder);
    error TenderNoTotalRequested(uint256 id);
    error TenderNotSettled(uint256 id);

    modifier onlyIssuer() {
        require(SHARES.isAdmin(msg.sender) || SHARES.isAgent(msg.sender), TenderNotIssuer(msg.sender));
        _;
    }

    constructor(CharterShares shares) {
        SHARES = shares;
    }

    function offerCount() external view returns (uint256) {
        return _offers.length;
    }

    function getOffer(uint256 id) external view returns (Offer memory) {
        return _offers[id];
    }

    /// @notice Returns the caller's own encrypted tender handle for an offer (decryptable by them).
    function myTender(uint256 id) external view returns (euint64) {
        return _tender[id][msg.sender];
    }

    /// @notice Opens a buyback. Escrows `pricePerShare * maxShares` of `paymentToken` from the
    /// issuer's treasury (the caller must have approved this contract as an operator on it first).
    function openOffer(
        IERC7984 paymentToken,
        uint64 pricePerShare,
        uint64 maxShares,
        uint48 votingPeriod
    ) external onlyIssuer returns (uint256 id) {
        // Escrow (max payout) must fit euint64; this also bounds every per-holder payment.
        require(
            pricePerShare > 0 && maxShares > 0 && uint256(pricePerShare) * maxShares <= type(uint64).max,
            TenderBadParams()
        );

        euint64 escrow = FHE.asEuint64(pricePerShare * maxShares);
        FHE.allowTransient(escrow, address(paymentToken));
        paymentToken.confidentialTransferFrom(msg.sender, address(this), escrow);

        euint64 zero = FHE.asEuint64(0);
        FHE.allowThis(zero);

        id = _offers.length;
        _offers.push(
            Offer({
                treasury: msg.sender,
                paymentToken: address(paymentToken),
                pricePerShare: pricePerShare,
                maxShares: maxShares,
                deadline: uint48(SHARES.clock()) + votingPeriod,
                totalTendered: zero,
                totalRequested: false,
                totalSettled: false,
                totalTenderedClear: 0
            })
        );
        emit OfferOpened(id, address(paymentToken), pricePerShare, maxShares, _offers[id].deadline);
    }

    /// @notice Tenders an encrypted quantity of shares into an open offer. The tender is capped at
    /// the holder's current balance, so a holder can never sell more than they hold.
    function tender(uint256 id, externalEuint64 encryptedQuantity, bytes calldata inputProof) external {
        Offer storage o = _offers[id];
        require(SHARES.clock() <= o.deadline, TenderClosed(id));
        require(!tendered[id][msg.sender], TenderAlready(id, msg.sender));
        tendered[id][msg.sender] = true;

        euint64 requested = FHE.fromExternal(encryptedQuantity, inputProof);
        euint64 balance = SHARES.allowBalanceAccess(msg.sender);
        euint64 qty = FHE.isInitialized(balance) ? FHE.min(requested, balance) : FHE.asEuint64(0);

        FHE.allowThis(qty);
        FHE.allow(qty, msg.sender);
        _tender[id][msg.sender] = qty;

        o.totalTendered = FHE.add(o.totalTendered, qty);
        FHE.allowThis(o.totalTendered);

        emit Tendered(id, msg.sender);
    }

    /// @notice After the deadline, makes the aggregate tendered amount publicly decryptable.
    function requestTotal(uint256 id) external {
        Offer storage o = _offers[id];
        require(SHARES.clock() > o.deadline, TenderNotClosed(id));
        FHE.makePubliclyDecryptable(o.totalTendered);
        o.totalRequested = true;
        emit TotalRequested(id);
    }

    /// @notice Settles the disclosed aggregate with its KMS proof. Anyone may relay.
    function settleTotal(uint256 id, uint64 clearTotal, bytes calldata decryptionProof) external {
        Offer storage o = _offers[id];
        require(o.totalRequested, TenderNoTotalRequested(id));

        bytes32[] memory handles = new bytes32[](1);
        handles[0] = euint64.unwrap(o.totalTendered);
        FHE.checkSignatures(handles, abi.encode(clearTotal), decryptionProof);

        o.totalTenderedClear = clearTotal;
        o.totalSettled = true;
        emit TotalSettled(id, clearTotal, clearTotal > o.maxShares);
    }

    /// @notice Fills a batch of holders: pulls their accepted shares to the treasury and pays them
    /// in the confidential payment token. Oversubscribed offers are scaled pro-rata on ciphertext.
    /// Each holder must have approved this contract as an operator on the share token.
    function claim(uint256 id, address[] calldata holders) external onlyIssuer {
        Offer storage o = _offers[id];
        require(o.totalSettled, TenderNotSettled(id));
        bool oversubscribed = o.totalTenderedClear > o.maxShares;

        IERC7984 payToken = IERC7984(o.paymentToken);
        for (uint256 i = 0; i < holders.length; i++) {
            address holder = holders[i];
            require(!claimed[id][holder], TenderAlready(id, holder));
            claimed[id][holder] = true;

            euint64 qty = _tender[id][holder];
            if (!FHE.isInitialized(qty)) continue;

            euint64 accepted = oversubscribed ? FHE.div(FHE.mul(qty, o.maxShares), o.totalTenderedClear) : qty;

            FHE.allowTransient(accepted, address(SHARES));
            SHARES.confidentialTransferFrom(holder, o.treasury, accepted);

            euint64 payment = FHE.mul(accepted, o.pricePerShare);
            FHE.allowTransient(payment, o.paymentToken);
            payToken.confidentialTransfer(holder, payment);
        }
        emit Claimed(id, holders);
    }

    /// @notice Returns unspent escrow (undersubscribed remainder) to a chosen address.
    function sweep(IERC7984 token, address to) external onlyIssuer {
        euint64 balance = token.confidentialBalanceOf(address(this));
        if (FHE.isInitialized(balance)) {
            token.confidentialTransfer(to, balance);
        }
    }
}

contracts/DemoShareFaucet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FHE, euint64} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {CharterShares} from "./CharterShares.sol";

/// @title DemoShareFaucet - one-time testnet share grants for self-serve demos
contract DemoShareFaucet is ZamaEthereumConfig {
    CharterShares public immutable SHARES;
    uint64 public constant GRANT = 1000;

    mapping(address account => bool) public claimed;

    error AlreadyClaimed(address account);

    constructor(CharterShares shares) {
        SHARES = shares;
    }

    function claim() external {
        require(!claimed[msg.sender], AlreadyClaimed(msg.sender));
        claimed[msg.sender] = true;

        euint64 amount = FHE.asEuint64(GRANT);
        FHE.allowThis(amount);
        FHE.allowTransient(amount, address(SHARES));
        SHARES.confidentialMint(msg.sender, amount);
    }
}

contracts/DividendDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import {FHE, euint64} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {IERC7984} from "@openzeppelin/confidential-contracts/interfaces/IERC7984.sol";
import {CharterShares} from "./CharterShares.sol";

/// @title DividendDistributor — pro-rata distributions over encrypted holdings
/// @notice The issuer declares a distribution with a public pool amount in any ERC7984
/// payment token. Each investor's payout is computed on-chain from their encrypted
/// share balance: payout = balance * pool / totalSharesOnRecord. The pool total is
/// public and verifiable; every individual payout stays encrypted, decryptable only
/// by its recipient (and any observer they appointed).
///
/// Record-date integrity: declarations require the share token to be paused, so
/// balances cannot move between the record date and payout batches.
contract DividendDistributor is ZamaEthereumConfig {
    struct Distribution {
        address token;
        uint64 pool;
        uint64 totalShares;
        uint48 declaredAt;
    }

    CharterShares public immutable SHARES;

    Distribution[] private _distributions;
    mapping(uint256 distributionId => mapping(address investor => bool)) public paid;

    event DistributionDeclared(uint256 indexed id, address indexed token, uint64 pool, uint64 totalShares);
    event BatchPaid(uint256 indexed id, address[] investors);
    event Swept(address indexed token, address indexed to);

    error DistributorNotIssuer(address caller);
    error DistributorNoRecordSupply();
    error DistributorPoolOverflow();
    error DistributorSharesNotPaused();
    error DistributorStaleSupply();
    error DistributorAlreadyPaid(uint256 id, address investor);

    modifier onlyIssuer() {
        require(SHARES.isAdmin(msg.sender) || SHARES.isAgent(msg.sender), DistributorNotIssuer(msg.sender));
        _;
    }

    constructor(CharterShares shares) {
        SHARES = shares;
    }

    function distributionCount() external view returns (uint256) {
        return _distributions.length;
    }

    function getDistribution(uint256 id) external view returns (Distribution memory) {
        return _distributions[id];
    }

    /// @notice Declares a distribution and pulls `poolAmount` of `payToken` from the
    /// caller's treasury. The caller must have set this contract as an operator on
    /// `payToken` beforehand.
    function declare(IERC7984 payToken, uint64 poolAmount) external onlyIssuer returns (uint256 id) {
        require(SHARES.paused(), DistributorSharesNotPaused());
        uint64 totalShares = SHARES.totalSharesOnRecord();
        require(totalShares > 0, DistributorNoRecordSupply());
        require(!SHARES.supplyDisclosureStale(), DistributorStaleSupply());
        // balance * pool must fit in euint64 for every balance <= totalShares
        require(poolAmount > 0 && uint256(poolAmount) * totalShares <= type(uint64).max, DistributorPoolOverflow());

        euint64 pool = FHE.asEuint64(poolAmount);
        FHE.allowTransient(pool, address(payToken));
        payToken.confidentialTransferFrom(msg.sender, address(this), pool);

        id = _distributions.length;
        _distributions.push(
            Distribution({token: address(payToken), pool: poolAmount, totalShares: totalShares, declaredAt: uint48(block.timestamp)})
        );
        emit DistributionDeclared(id, address(payToken), poolAmount, totalShares);
    }

    /// @notice Pays a batch of investors their pro-rata cut of distribution `id`.
    /// Keep batches small (~15 investors) to stay within the per-transaction HCU budget.
    function payBatch(uint256 id, address[] calldata investors) external onlyIssuer {
        Distribution storage d = _distributions[id];
        require(SHARES.paused(), DistributorSharesNotPaused());

        IERC7984 token = IERC7984(d.token);
        for (uint256 i = 0; i < investors.length; i++) {
            address investor = investors[i];
            require(!paid[id][investor], DistributorAlreadyPaid(id, investor));
            paid[id][investor] = true;

            euint64 balance = SHARES.allowBalanceAccess(investor);
            if (!FHE.isInitialized(balance)) continue; // never held shares — zero payout

            euint64 payout = FHE.div(FHE.mul(balance, d.pool), d.totalShares);
            FHE.allowTransient(payout, d.token);
            token.confidentialTransfer(investor, payout);
        }
        emit BatchPaid(id, investors);
    }

    /// @notice Returns this contract's remaining balance of `token` (rounding dust,
    /// unclaimed remainders) to `to`.
    function sweep(IERC7984 token, address to) external onlyIssuer {
        euint64 balance = token.confidentialBalanceOf(address(this));
        if (FHE.isInitialized(balance)) {
            token.confidentialTransfer(to, balance);
        }
        emit Swept(address(token), to);
    }
}

